import React, { useEffect, useState } from "react";
import api from '../api';

export default function ProjectDetail({ project, onBack }) {
  const [sites, setSites] = useState([]);
  const [form, setForm] = useState({ name: "", latitude: "", longitude: "", land_area_ha: "" });

  const loadSites = async () => {
    const data = await api.getSites(project.id);
    setSites(data);
  };

  useEffect(() => {
    loadSites();
  }, [project.id]);

  const addSite = async (e) => {
    e.preventDefault();
    await api.createSite(project.id, {
      ...form,
      latitude: parseFloat(form.latitude),
      longitude: parseFloat(form.longitude),
      land_area_ha: form.land_area_ha ? parseFloat(form.land_area_ha) : null,
    });
    setForm({ name: "", latitude: "", longitude: "", land_area_ha: "" });
    loadSites();
  };

  const handleFetchData = async (siteId) => {
    await api.fetchEnvironmentalData(project.id, siteId);
    alert("Environmental data fetched.");
  };

  return (
    <div style={{ maxWidth: 800, margin: "40px auto", fontFamily: "sans-serif" }}>
      <button onClick={onBack}>← Back to Projects</button>
      <h2>{project.name}</h2>

      <h3>Sites</h3>
      <form onSubmit={addSite} style={{ display: "flex", gap: 8, marginBottom: 20, flexWrap: "wrap" }}>
        <input placeholder="Site name" value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} required />
        <input placeholder="Latitude" value={form.latitude} onChange={(e) => setForm({ ...form, latitude: e.target.value })} required />
        <input placeholder="Longitude" value={form.longitude} onChange={(e) => setForm({ ...form, longitude: e.target.value })} required />
        <input placeholder="Land area (ha)" value={form.land_area_ha} onChange={(e) => setForm({ ...form, land_area_ha: e.target.value })} />
        <button type="submit">+ Add Site</button>
      </form>

      <table width="100%" cellPadding={8} style={{ borderCollapse: "collapse" }}>
        <thead>
          <tr style={{ borderBottom: "1px solid #ccc" }}>
            <th align="left">Name</th>
            <th align="left">Lat, Lon</th>
            <th align="left">Land area (ha)</th>
            <th align="left"></th>
          </tr>
        </thead>
        <tbody>
          {sites.map((s) => (
            <tr key={s.id} style={{ borderBottom: "1px solid #eee" }}>
              <td>{s.name}</td>
              <td>{s.latitude}, {s.longitude}</td>
              <td>{s.land_area_ha ?? "-"}</td>
              <td>
                <button onClick={() => handleFetchData(s.id)}>Fetch data</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
